#include <iostream>
using namespace std;
class Solution {
public:
    int deque(int n, int k) {
        int head = 0;
        int size = 0;

        if (size >= k) {
            cout << "Dequeued element is " << nums[k] << endl;
        } else {
            head = (head + k - size + n - 1) % (n - 1);
            cout << "Dequeued element is " << nums[head] << endl;
        }

        return nums[k];
    }
};

int main() {
    Solution solution;
    int n, k;
    cin >> n >> k;

    solution.deque(n, k);

    return 0;
}
